// Get previous month
const now = new Date();
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const monthStr = prevMonth.toISOString().slice(0, 7);
const monthLabel = prevMonth.toLocaleDateString('en-US', {month: 'long', year: 'numeric'});
return [{json: {month: monthStr, monthLabel, apiBase: $env.API_BASE_URL}}];

const summary = $('Get Monthly Summary').first().json;
const netWorth = $('Get Net Worth').first().json;
const budgetsData = $('Get Budget Performance').first().json;
const monthLabel = $('Compute Previous Month').first().json.monthLabel;

const fmtUSD = (n) => '$' + Math.abs(n || 0).toLocaleString('en-US', {minimumFractionDigits: 0, maximumFractionDigits: 0});
const fmtPct = (n) => ((n || 0) * 100).toFixed(1) + '%';

const income = summary.total_income || 0;
const expenses = summary.total_expenses || 0;
const savings = summary.savings || 0;
const savingsRate = summary.savings_rate || 0;
const netWorthValue = netWorth.net_worth_usd || 0;

const budgets = budgetsData.budgets || [];
const overBudget = budgets.filter(b => b.pct_used > 100);
const topCategories = Object.entries(summary.by_category || {})
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3);

let lines = [];
lines.push(`*Monthly Finance Report — ${monthLabel}*`);
lines.push('');
lines.push(`*Income & Expenses*`);
lines.push(`Income: ${fmtUSD(income)}`);
lines.push(`Expenses: ${fmtUSD(expenses)}`);
lines.push(`Net Savings: ${savings >= 0 ? '+' : ''}${fmtUSD(savings)}`);
lines.push(`Savings Rate: ${fmtPct(savingsRate)} ${savingsRate >= 0.2 ? '(target met)' : savingsRate >= 0.1 ? '(below 20% target)' : '(below 10% — review expenses)'}`);
lines.push('');
lines.push(`*Net Worth*`);
lines.push(`Current: ${fmtUSD(netWorthValue)}`);

if (topCategories.length > 0) {
  lines.push('');
  lines.push('*Top Expense Categories*');
  topCategories.forEach(([cat, amt]) => {
    lines.push(`- ${cat}: ${fmtUSD(amt)}`);
  });
}

if (overBudget.length > 0) {
  lines.push('');
  lines.push(`*Budget Overruns (${overBudget.length})*`);
  overBudget.slice(0, 3).forEach(b => {
    lines.push(`- ${b.categories?.name || 'Unknown'}: ${b.pct_used?.toFixed(0)}% used`);
  });
}

lines.push('');
lines.push('[View Finance Report](https://invest.ovelha.us/finance)');

return [{json: {message: lines.join('\n')}}];
